import { useState } from 'react';
import { Handle, Position } from 'reactflow';

export const InputNode = ({ id, data }) => {
  const [currName, setCurrName] = useState(data?.inputName || id.replace('customInput-', 'input_'));
  const [inputType, setInputType] = useState(data?.inputType || 'Text');

  const handleNameChange = (e) => {
    setCurrName(e.target.value);
    data.inputName = e.target.value; // sync with React Flow
  };

  const handleTypeChange = (e) => {
    setInputType(e.target.value);
    data.inputType = e.target.value;
  };

  return (
    <div className="vs-node input-node">
      <div className="vs-node-header">Input</div>
      <div className="vs-node-body">
        <label htmlFor={`${id}-name`}>
          Name:
          <input
            id={`${id}-name`}
            type="text"
            value={currName}
            onChange={handleNameChange}
          />
        </label>
        <label htmlFor={`${id}-type`}>
          Type:
          <select id={`${id}-type`} value={inputType} onChange={handleTypeChange}>
            <option value="Text">Text</option>
            <option value="File">File</option>
          </select>
        </label>
      </div>
      <Handle type="source" position={Position.Right} id={`${id}-value`} />
    </div>
  );
};
